/**
 * The three Stipt brand fonts, embedded as base64 for use ONLY inside PDF
 * HTML templates rendered by headless Chromium (renderHtmlToPdf). This is
 * deliberate: an external <link> to Google Fonts inside a PDF template is
 * exactly the kind of external-resource fetch that has hung headless
 * Chrome before (see renderHtmlToPdf's own timeout comments) — embedding
 * the font bytes directly means Chrome never makes a network request to
 * render them, so there's nothing to hang on.
 *
 * Fetched once from Google Fonts' own CDN (fonts.gstatic.com) and
 * committed here as static data — NOT fetched at request time. Latin
 * subset (covers Dutch/English, including é/ë/ï/ö/ü etc.) so arbitrary
 * contractor/client-entered text (names, addresses, notes) renders
 * correctly, not just this template's own fixed labels.
 *
 * NOT used by the react-pdf built-in quote design (ProposalPDF/QuotePDF/
 * SignedQuotePDF) — those use react-pdf's own font-registration API,
 * which needs a different mechanism entirely, and deliberately keep the
 * safe built-in Helvetica rather than take on custom font embedding in a
 * second, differently-risked rendering pipeline.
 */

/** Space Grotesk, weight 700 — headings/labels (STIPT_FONT_CSS's --font-display). */
const SPACE_GROTESK_BOLD_B64 = ''

/** Hanken Grotesk — a variable font (one file covers weights 400-700) — body text. */
const HANKEN_GROTESK_B64 = ''

/** Space Mono, weight 400 — numbers (amounts, VAT, invoice/quote numbers). */
const SPACE_MONO_REGULAR_B64 = ''

/** Space Mono, weight 700 — bold numbers (totals). */
const SPACE_MONO_BOLD_B64 = ''

/**
 * Ready-to-splice @font-face block, defining --font-display / --font-body
 * / --font-mono custom properties so PDF templates can reference them the
 * exact same way the portal's own CSS does (see globals.css).
 */
export const STIPT_PDF_FONT_CSS = `
  @font-face {
    font-family: 'Space Grotesk';
    font-style: normal;
    font-weight: 700;
    src: url(data:font/woff2;base64,${SPACE_GROTESK_BOLD_B64}) format('woff2');
  }
  @font-face {
    font-family: 'Hanken Grotesk';
    font-style: normal;
    font-weight: 400 700;
    src: url(data:font/woff2;base64,${HANKEN_GROTESK_B64}) format('woff2');
  }
  @font-face {
    font-family: 'Space Mono';
    font-style: normal;
    font-weight: 400;
    src: url(data:font/woff2;base64,${SPACE_MONO_REGULAR_B64}) format('woff2');
  }
  @font-face {
    font-family: 'Space Mono';
    font-style: normal;
    font-weight: 700;
    src: url(data:font/woff2;base64,${SPACE_MONO_BOLD_B64}) format('woff2');
  }
  :root {
    --font-display: 'Space Grotesk', ui-sans-serif, system-ui, sans-serif;
    --font-body: 'Hanken Grotesk', system-ui, -apple-system, sans-serif;
    --font-mono: 'Space Mono', ui-monospace, monospace;
  }
`
